package config

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/pelletier/go-toml/v2"
)

type Config struct {
	BaseURL        string    `toml:"base_url"`
	AuthHeaderVal  string    `toml:"auth_header"`
	AuthSource     string    `toml:"-"`
	AccessToken    string    `toml:"access_token"`
	RefreshToken   string    `toml:"refresh_token"`
	TokenExpiry    time.Time `toml:"token_expiry"`
	ClientID       string    `toml:"client_id"`
	ClientSecret   string    `toml:"client_secret"`
	Path           string    `toml:"-"`
	APIKey         string    `toml:"api_key"`
	PrivateKeyPath string    `toml:"private_key_path"`
	ReadOnly       bool      `toml:"read_only"`

	privateKey *rsa.PrivateKey
}

func Load(configPath string) (*Config, error) {
	cfg := &Config{
		BaseURL: "https://api.elections.kalshi.com/trade-api/v2",
	}

	path := configPath
	if path == "" {
		path = os.Getenv("KALSHI_CONFIG")
	}
	if path == "" {
		home, _ := os.UserHomeDir()
		path = filepath.Join(home, ".config", "kalshi-pp-cli", "config.toml")
	}
	cfg.Path = path

	data, err := os.ReadFile(path)
	if err == nil {
		if err := toml.Unmarshal(data, cfg); err != nil {
			return nil, fmt.Errorf("parsing config %s: %w", path, err)
		}
	}

	if v := os.Getenv("KALSHI_API_KEY"); v != "" {
		cfg.APIKey = v
		cfg.AuthSource = "env:KALSHI_API_KEY"
	}
	if v := os.Getenv("KALSHI_PRIVATE_KEY_PATH"); v != "" {
		cfg.PrivateKeyPath = v
	}
	if v := os.Getenv("KALSHI_PRIVATE_KEY"); v != "" {
		key, err := parseRSAPrivateKey([]byte(v))
		if err != nil {
			return nil, fmt.Errorf("parsing KALSHI_PRIVATE_KEY: %w", err)
		}
		cfg.privateKey = key
	}

	if v := os.Getenv("KALSHI_BASE_URL"); v != "" {
		cfg.BaseURL = v
	}
	if v := os.Getenv("KALSHI_ENV"); v == "demo" {
		cfg.BaseURL = "https://demo-api.kalshi.co/trade-api/v2"
	}

	if v := os.Getenv("KALSHI_READ_ONLY"); v == "1" || strings.EqualFold(v, "true") {
		cfg.ReadOnly = true
	}

	if cfg.privateKey == nil && cfg.PrivateKeyPath != "" {
		keyPath := cfg.PrivateKeyPath
		if strings.HasPrefix(keyPath, "~/") {
			home, _ := os.UserHomeDir()
			keyPath = filepath.Join(home, keyPath[2:])
		}
		keyData, err := os.ReadFile(keyPath)
		if err != nil {
			return nil, fmt.Errorf("reading private key from %s: %w", keyPath, err)
		}
		key, err := parseRSAPrivateKey(keyData)
		if err != nil {
			return nil, fmt.Errorf("parsing private key from %s: %w", keyPath, err)
		}
		cfg.privateKey = key
	}

	return cfg, nil
}

// PrivateKey returns the parsed RSA private key, or nil if not configured.
func (c *Config) PrivateKey() *rsa.PrivateKey {
	return c.privateKey
}

// HasAuth returns true when both the access key id and the private key are loaded.
func (c *Config) HasAuth() bool {
	return c.APIKey != "" && c.privateKey != nil
}

// AuthHeader returns the access key id; the full RSA-PSS signed headers are
// computed per request inside the client.
func (c *Config) AuthHeader() string {
	if c.AuthHeaderVal != "" {
		return c.AuthHeaderVal
	}
	return c.APIKey
}

func parseRSAPrivateKey(data []byte) (*rsa.PrivateKey, error) {
	block, _ := pem.Decode(data)
	if block == nil {
		return nil, fmt.Errorf("no PEM block found in key data")
	}
	if key, err := x509.ParsePKCS8PrivateKey(block.Bytes); err == nil {
		rsaKey, ok := key.(*rsa.PrivateKey)
		if !ok {
			return nil, fmt.Errorf("PKCS8 key is not RSA")
		}
		return rsaKey, nil
	}
	rsaKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return nil, fmt.Errorf("failed to parse private key (tried PKCS8 and PKCS1): %w", err)
	}
	return rsaKey, nil
}

func applyAuthFormat(format string, replacements map[string]string) string {
	if format == "" {
		return ""
	}
	for key, value := range replacements {
		format = strings.ReplaceAll(format, "{"+key+"}", value)
	}
	if strings.Contains(format, "{") {
		return ""
	}
	return format
}

func (c *Config) SaveTokens(clientID, clientSecret, accessToken, refreshToken string, expiry time.Time) error {
	c.ClientID = clientID
	c.ClientSecret = clientSecret
	c.AccessToken = accessToken
	c.RefreshToken = refreshToken
	c.TokenExpiry = expiry
	return c.save()
}

// SaveCredential persists a single API credential to the field that
// AuthHeader() consults for api_key auth. Writing to AccessToken (the
// bearer slot) would silently no-op since AuthHeader() reads the env-var-
// derived field, not AccessToken, when Auth.Type == "api_key".
//
// The clears precede the assignment so a canonical env-var whose placeholder
// collides with a builtin tag (e.g. an env var named XXX_ACCESS_TOKEN
// resolving to the AccessToken field) ends up holding the new token.
func (c *Config) SaveCredential(token string) error {
	c.AuthHeaderVal = ""
	c.AccessToken = ""
	c.APIKey = token
	return c.save()
}

func (c *Config) ClearTokens() error {
	c.AccessToken = ""
	c.RefreshToken = ""
	c.TokenExpiry = time.Time{}
	c.APIKey = ""
	return c.save()
}

func (c *Config) save() error {
	dir := filepath.Dir(c.Path)
	if err := os.MkdirAll(dir, 0o700); err != nil {
		return fmt.Errorf("creating config dir: %w", err)
	}
	data, err := toml.Marshal(c)
	if err != nil {
		return fmt.Errorf("marshaling config: %w", err)
	}
	return os.WriteFile(c.Path, data, 0o600)
}

var _ = applyAuthFormat
